#include <stdio.h>
#include <stdlib.h>
#include <liblinear/linear.h>

int main() {
 // Load data
 double X[100][4];
 double y[100];
 int n = 100;

 // Split data into training and test sets
 int train_size = 80;
 int test_size = 20;
 double X_train[train_size][4];
 double y_train[train_size];
 double X_test[test_size][4];
 double y_test[test_size];

 // Train logistic regression model
 struct problem prob;
 prob.l = train_size;
 prob.n = 4;
 prob.x = X_train;
 prob.y = y_train;
 struct parameter param;
 param.solver_type = L2R_LR;
 param.C = 1;
 param.eps = 0.01;
 struct model* model = train(&prob, &param);

 // Make predictions on test set
 double y_pred[test_size];
 for (int i = 0; i < test_size; i++) {
 y_pred[i] = predict(model, X_test[i]);
 }

 // Evaluate model performance
 int correct = 0;
 for (int i = 0; i < test_size; i++) {
 if (y_pred[i] == y_test[i]) {
 correct++;
 }
 }
 double accuracy = (double) correct / test_size;
 printf("Accuracy: %f\n", accuracy);

 return 0;
}
